#include<bits/stdc++.h>
using namespace std;
const int N = 1100;
string add(string a,string b){//高精加 
	string c;
	reverse(a.begin(),a.end());
	reverse(b.begin(),b.end());
	int temp = 0;
	for(int i=0;i<a.size()||i<b.size();i++){
		if(i < a.size()) temp += a[i] - '0';
		if(i < b.size()) temp += b[i] - '0';
		c += temp%10 + '0';
		temp /= 10;
	}
	if(temp) c += '1';
	reverse(c.begin(),c.end());
	return c;
}
int n,m,a[N];
string f[N+N][N];
void solve(){
	cin >> n;
	f[0][0] = "1";
	for(int i=1;i<=n+n;i++){
		for(int j=1;j<=n;j++){
			if(j <= i && j >= i-j) 
				f[i][j] = add(f[i-1][j-1],f[i-1][j]);
		}
	}
	cout << f[n+n][n] << "\n";
}
signed main(){
	ios::sync_with_stdio(false);cin.tie(0);cout.tie(0);
	int t = 1;
	while(t--) solve();
	return 0;
}
